var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경! 퇴로를 차단해 주세요!","JPN":"アレン卿！　退路を遮断してください！","ENG":"Dame Liv! Seal off any escape routes!","TWN":"莉芙卿！從後面包抄！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오키도키! 나한테 맡기시라!","JPN":"りょーかい！　私に任せて！","ENG":"Okie dokie! You can leave it to me!","TWN":"Okie Dokie！包在我身上！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"기록 분석 완료. 제 행동반경이 지속적으로 좁아지고 있군요.","JPN":"記録分析完了。私の行動半径が徐々に狭くなっていますね。","ENG":"Record analysis complete. My freedom of maneuver continues to diminish.","TWN":"紀錄分析完畢，我的行動半徑持續縮小中。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"인간형 적을 상대로 체계적인 훈련을 받았다고 추정됩니다. 그림자 전문이라도 됩니까.","JPN":"人間型の敵を相手に体系的な訓練を受けたと推定されます。シャドウ専門なのですか。","ENG":"It leads me to hypothesize that you have received systematic combat training against humanoid adversaries. Is your expertise in hunting Shadows?","TWN":"推測曾經接受過對抗人型敵人的系統化訓練，可以說是專門對付暗影的嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"적의 질문에는 대답해 드릴 수가 없군요. 얌전히 투항하시면 자세하게 설명해 드리죠.","JPN":"敵の質問にはお答えできません。大人しく投降したら詳しく説明して差し上げましょう。","ENG":"I will not answer my enemy's question. I'd be happy to elucidate in detail if you surrender though.","TWN":"對於敵人的問題我們無可奉告，若是你乖乖就範，那我可以跟你詳細說明。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"절대 투항하지 마! 부단장한테 설명 듣다간 하루 종일 안 끝난다구!","JPN":"絶対投降しないで！　副団長が説明し始めたら一日じゃ終わらないんだよ！","ENG":"Don't do it! Unless you want to hear her talk for an entire day!","TWN":"你千萬不可以投降！副團長的說明很可能一整天都聽不完！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경! 적과 싸우는 와중에 동료를 헐뜯다니요!","JPN":"アレン卿！　敵との戦闘中に同僚の悪口を言ってはいけませんよ！","ENG":"Dame Liv! How could you disparage your colleague in the middle of a fight?!","TWN":"莉芙卿！你竟然在和敵人交手時抹黑同伴！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"야, 저……. 저 사람들 광대라고 하지 않았냐?","JPN":"おい、ちょっと……あの人たちって道化だよね？","ENG":"Hey… Aren't those folks supposed to be clowns?","TWN":"喂……你不是說那些人是小丑嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"사실 엄청 강한 거 아냐? 좀 멋있어 보이는데……?","JPN":"実はすごく強いんじゃない？　ちょっとかっこよく見えるんだけど……？","ENG":"What if they're actually super strong? They're starting to look kinda cool to me…","TWN":"他們根本超強好不好？！看起來有點帥欸……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"웃기지 마! 정규 태스크포스들도 깨졌다는데 돈도 없이 코스프레나 하는 컨셉 등신들이 어떻게 이겨!","JPN":"バカいうな！　正規タスクフォースカンパニーもボコられたのに、金ももらわないコスプレしかできないオタク集団がどうやって勝つんだよ！","ENG":"Don't be ridiculous! That girl beat even the legit TASKFORCEs, I hear. Those stupid cosplayers don't stand a chance!","TWN":"拜託！連正規特遣勢力都打輸她，\\n那些玩Cosplay的怎麼可能打得贏！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"저 애가 분명 영상에서 봤던 것처럼 쇠파이프로 개박살을 내 줄 거야! 그래야 우리 영상이 뜨지!","JPN":"ネットでみた映像みたいに、きっとあの子が鉄パイプでめちゃくちゃに\\nしてくれるよ！　そうしてくれなきゃ俺たちの動画の再生数が伸びないだろ！","ENG":"She'll kick their butts with her pipe, just as I saw in that other video! And then our video will go viral!","TWN":"那個女生一定會像影片裡看到的一樣，用鐵管打爆他們啦！這樣我們的影片才會爆紅啊！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"흠……. 평범한 공격으로는 저지하기 어려운가.","JPN":"ふむ……平凡な攻撃では阻止できないか。","ENG":"Hmm... It appears ordinary attacks won't stop her.","TWN":"嗯……普通的攻擊可能很難攔下她。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장! 리브 경! 물러서도록!","JPN":"副団長！　リブ！　下がれ！","ENG":"Deputy! Dame Liv! Fall back!","TWN":"副團長！莉芙卿！閃開！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"고에너지 반응이 검출되었습니다. 이번 공격은 진심이군요.","JPN":"高エネルギー反応が検出されました。今回の攻撃は本気のようですね。","ENG":"High energy signature detected. You must be putting your heart and soul in this attack.","TWN":"檢測到高能量反應，看來這次的攻擊是認真的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그대의 활약상에 대해서는 알고 있다. 평범한 공격으로 막을 생각은 없었어.","JPN":"君の活躍ぶりについては承知している。ただの攻撃で止めるつもりなどない。","ENG":"Your reputation precedes you. I knew it'd take something extra special to stop you.","TWN":"我知道你的能力，普通的攻擊是攔不住你的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"버고 소드, 전개!","JPN":"ヴァルゴソード、展開！","ENG":"Virgo Sword Draw!","TWN":"布林加夫之劍，出動！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_05"},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"파도쳐라, 섬광!!","JPN":"うなれ、閃光！！","ENG":"Surge, Flash!!","TWN":"閃閃吧，閃光！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"미…… 미친……. 저런 빛기둥이 인간한테서 나온다고……?","JPN":"お……おい……あんな光の柱を人間が放つとか嘘だろ……？","ENG":"T-that's insane! Did that pillar of light seriously just come from a person?","TWN":"超狂……從人類身上發出那種光束……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"야……. 아까 걔가 아니라 저 사람이 S급 아니야……?","JPN":"なあ……鉄パイプの子じゃなくて、あの人がS級なんじゃ……？","ENG":"Hey… You sure the Grade S isn't that lady instead of the pipe girl?","TWN":"喂……不是剛才那個人啦，那個人不是S級……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"우와. 역시 우리 중에서 단장이 제일 화끈해.","JPN":"わあ、やっぱりうちの団長が一番決まってるぅ！","ENG":"Woah. I guess the Commander's the boss for a reason.","TWN":"哇，團長果然是我們當中最霸氣的！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"감탄할 때가 아닙니다! 휘말린 수배자를 수색해야죠!","JPN":"感心している場合ではありません！　姿が見えなくなった指名手配犯を捜索するべきです！","ENG":"Now's not the time to linger in idle awe! We must find the felon swept up in there!","TWN":"現在不是讚嘆的時候！要先去拘捕通緝犯吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……아냐, 부단장. 부상 입은 단원들부터 추스르도록.","JPN":"……よせ、副団長。負傷した団員たちを先にまとめてくれ。","ENG":"…No, Deputy Commander. Tend to our wounded first.","TWN":"……不，副團長，先處理受傷的團員們。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"무슨 일이시죠, 단장님?","JPN":"どうしたのですか、団長？","ENG":"What's wrong, Commander?","TWN":"團長，怎麼了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"빛을 방출하는 순간 보였어. 지면에 생긴 균열을 통해 지하로 들어가더군.","JPN":"光を放出した瞬間見えた。地面にできた亀裂から地下に入っていった。","ENG":"I saw it the moment I unleashed the light. She vanished underground through the fissures on the ground.","TWN":"剛才放出光束的瞬間，我看到她從地面產生的裂縫往地底下去了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기사가 한 번 뱉은 말을 어길 수는 없지. 나를 넘어서 갔으니, 내 패배다.","JPN":"騎士たる者、一度口に出した言葉は戻せない。私を越えて行ったのだから、私の敗北だ。","ENG":"A knight never goes back on her word. She went through me, so I concede defeat.","TWN":"騎士一言既出駟馬難追。她確實是越過我了，我認輸。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이 아래에는 지하철도가 있습니다. 방향만 안다면 아무 저항 없이 제프티 바이오테크로 향할 겁니다.","JPN":"この下には地下鉄があります。方向さえ特定できたら、\\n何の問題もなくジェフティ・バイオテックに辿り着くでしょう。","ENG":"The subway tracks run under here. She'll make it straight to Jehuty Biotech without any resistance if she knows which way to go.","TWN":"這下面有地鐵，等於只要知道方向，就可以直達傑夫堤生物科技。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"관리국에서 전해 들었던 내용이 사실이라면 방치하기엔 위험한 인물입니다. 쫓으셔야 합니다, 단장님.","JPN":"管理局から共有された内容が事実であれば、放置するにはとても危険な人物です。追いかけるべきです、団長。","ENG":"She is far too dangerous to leave unchecked if what the Administration said is true. We must pursue her, Commander.","TWN":"如果管理局傳達的內容是事實，那放走她會有危險。團長，我們必須追上去。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……정말 그럴까?","JPN":"……本当にそうだろうか？","ENG":"…Are you sure about that?","TWN":"……真的是那樣嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"의료 지원단을 잔혹하게 살해하고, 연구시설 하나를 무너뜨린 자라고 하기엔…….","JPN":"医療支援団を残酷に殺害し、研究施設を丸ごと崩壊させた者ということだが……","ENG":"For someone who allegedly massacred aid workers and demolished a research facility…","TWN":"殘忍地殺害義診團隊，還剷平一個研究設施，若是如此……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"단원들 중에 전사자는 한 명도 없었어.","JPN":"団員の中に戦死者は一人もいなかった。","ENG":"She did not kill a single member of our order.","TWN":"那為什麼騎士團當中都沒有人喪命？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그건……. 확실히, 부정하기 어렵습니다만…….","JPN":"それは……確かに、否定できませんが……","ENG":"Well… I suppose there's no denying that... But still…","TWN":"是……我也無法否認……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"우리만이 아니다. 다른 태스크포스들도 부상 때문에 입원하긴 했지만 목숨은 무사했어.","JPN":"我々だけではない。他のタスクフォースカンパニーも負傷して入院した者はいたが、命に別状はない。","ENG":"It's not just us either. The other TASKFORCEs have been injured and hospitalized, but otherwise all survived.","TWN":"不只是我們，其他的特遣勢力也是，雖然是有受傷住院，卻沒人因此喪命。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"의견을 듣고 싶군. 부단장은 저 자가 진정 다른 이들의 말처럼 잔혹한 범죄자 같나?","JPN":"意見を求めたい。副団長は、あの者が本当に残酷な犯罪者だと思えるか？","ENG":"I'd like to hear what you think. Does she strike you as the merciless killer they make her out to be?","TWN":"我想聽聽副團長的想法，你認為，她真的是別人口中所說的殘忍罪犯嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};